process.env.STORAGE_DIR = "test-storage"; // needed for tests to run

// We need to test the file extension resolution from content type
// The key scenario: when a URL like https://arxiv.org/pdf/2307.10265 is processed,
// the server returns application/pdf but the URL path has no standard file extension.
describe("processSingleFile with unknown extension and content-type fallback", () => {
  const path = require("path");
  const fs = require("fs");
  const { processSingleFile } = require("../../processSingleFile");
  const { WATCH_DIRECTORY, SUPPORTED_FILETYPE_CONVERTERS, ACCEPTED_MIMES } = require("../../utils/constants");

  // Test: filename with numeric "extension" like .10265 should fail with current code
  // This simulates the bug: a file downloaded from arxiv.org/pdf/2307.10265
  it("should fail when file has a non-standard extension like .10265", async () => {
    // Create a test file in the hotdir with a numeric "extension"
    const testFilename = "arxiv.org-pdf-2307-10265";
    const testFilePath = path.join(WATCH_DIRECTORY, testFilename);

    // Ensure hotdir exists
    if (!fs.existsSync(WATCH_DIRECTORY)) {
      fs.mkdirSync(WATCH_DIRECTORY, { recursive: true });
    }

    // Write a small test PDF file (minimal valid PDF)
    const minimalPdf = Buffer.from(
      "%PDF-1.4\n1 0 obj<</Type/Catalog/Pages 2 0 R>>endobj\n2 0 obj<</Type/Pages/Kids[3 0 R]/Count 1>>endobj\n3 0 obj<</Type/Page/MediaBox[0 0 612 792]/Parent 2 0 R>>endobj\nxref\n0 4\n0000000000 65535 f \n0000000009 00000 n \n0000000058 00000 n \n0000000115 00000 n \ntrailer<</Size 4/Root 1 0 R>>\nstartxref\n190\n%%EOF"
    );
    fs.writeFileSync(testFilePath, minimalPdf);

    const result = await processSingleFile(testFilename);

    // Clean up the test file
    try {
      fs.unlinkSync(testFilePath);
    } catch {}

    // This should currently FAIL because .10265 is not a known extension
    // and isTextType will return false for a PDF
    expect(result.success).toBe(false);
  });

  // Test: verify the key fix - when file extension is unknown but content type is known,
  // the system should be able to process the file correctly
  it("should report proper error message for non-standard extension", async () => {
    const testFilename = "arxiv.org-pdf-2307-10265";
    const testFilePath = path.join(WATCH_DIRECTORY, testFilename);

    if (!fs.existsSync(WATCH_DIRECTORY)) {
      fs.mkdirSync(WATCH_DIRECTORY, { recursive: true });
    }

    const minimalPdf = Buffer.from(
      "%PDF-1.4\n1 0 obj<</Type/Catalog/Pages 2 0 R>>endobj\n2 0 obj<</Type/Pages/Kids[3 0 R]/Count 1>>endobj\n3 0 obj<</Type/Page/MediaBox[0 0 612 792]/Parent 2 0 R>>endobj\nxref\n0 4\n0000000000 65535 f \n0000000009 00000 n \n0000000058 00000 n \n0000000115 00000 n \ntrailer<</Size 4/Root 1 0 R>>\nstartxref\n190\n%%EOF"
    );
    fs.writeFileSync(testFilePath, minimalPdf);

    const result = await processSingleFile(testFilename);

    try {
      fs.unlinkSync(testFilePath);
    } catch {}

    // Current bug: the reason message contains ".10265 not supported"
    expect(result.reason).toContain(".10265");
  });
});

