	    let filename = `${urlObj.hostname}-${slugify(
	      urlObj.pathname.replace(/\//g, "-"),
	      { lower: true }
	    )}`;

	    // Determine if we can get a file extension from the Content-Type header
	    // This handles URLs without explicit file extensions (e.g., https://arxiv.org/pdf/2307.10265)
	    const contentTypeHeader = res.headers.get("Content-Type")?.toLowerCase();
	    const contentTypeWithoutCharset = contentTypeHeader?.split(";")[0].trim();
	    const detectedExtension = extensionFromContentType(contentTypeWithoutCharset);
	    if (detectedExtension && !filename.endsWith(detectedExtension)) {
	      filename = filename + detectedExtension;
	    }

