const { WATCH_DIRECTORY, ACCEPTED_MIMES } = require("../constants");
const fs = require("fs");
const path = require("path");
const { pipeline } = require("stream/promises");
const { validURL } = require("../url");
const { default: slugify } = require("slugify");

/**
 * Build a reverse mapping from MIME type to file extension (ACCEPTED_MIMES => MIME type to extension)
 * This is used to determine the correct file extension from a Content-Type header
 * when the URL path does not contain an explicit file extension.
 * @returns {{[mimeType: string]: string}} - A mapping from MIME types to file extensions
 */
function getMimeExtensionMap() {
  const mimeMap = {};
  for (const [mimeType, extensions] of Object.entries(ACCEPTED_MIMES)) {
    // Use the first extension for each MIME type
    mimeMap[mimeType] = extensions[0];
  }
  return mimeMap;
}

/**
 * Determine the file extension from a Content-Type header value
 * @param {string|null} contentType - The Content-Type header value (e.g., "application/pdf")
 * @returns {string|null} - The file extension or null if not found
 */
function extensionFromContentType(contentType) {
  if (!contentType) return null;
  const mimeExtensionMap = getMimeExtensionMap();
  return mimeExtensionMap[contentType] || null;
}

/**
 * Download a file to the hotdir
 * @param {string} url - The URL of the file to download
 * @param {number} maxTimeout - The maximum timeout in milliseconds
 * @returns {Promise<{success: boolean, fileLocation: string|null, reason: string|null}>} - The path to the downloaded file
 */
async function downloadURIToFile(url, maxTimeout = 10_000) {
  if (!url || typeof url !== "string" || !validURL(url))
    return { success: false, reason: "Not a valid URL.", fileLocation: null };

  try {
    const abortController = new AbortController();
    const timeout = setTimeout(() => {
      abortController.abort();
      console.error(
        `Timeout ${maxTimeout}ms reached while downloading file for URL:`,
        url.toString()
      );
    }, maxTimeout);

    const res = await fetch(url, { signal: abortController.signal })
      .then((res) => {
        if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`);
        return res;
      })
      .finally(() => clearTimeout(timeout));

    const urlObj = new URL(url);
    let filename = `${urlObj.hostname}-${slugify(
      urlObj.pathname.replace(/\//g, "-"),
      { lower: true }
    )}`;

    // Determine if we can get a file extension from the Content-Type header
    // This handles URLs without explicit file extensions (e.g., https://arxiv.org/pdf/2307.10265)
    const contentTypeHeader = res.headers.get("Content-Type")?.toLowerCase();
    const contentTypeWithoutCharset = contentTypeHeader?.split(";")[0].trim();
    const detectedExtension = extensionFromContentType(contentTypeWithoutCharset);
    if (detectedExtension && !filename.endsWith(detectedExtension)) {
      filename = filename + detectedExtension;
    }

    const localFilePath = path.join(WATCH_DIRECTORY, filename);
    const writeStream = fs.createWriteStream(localFilePath);
    await pipeline(res.body, writeStream);

    console.log(`[SUCCESS]: File ${localFilePath} downloaded to hotdir.`);
    return { success: true, fileLocation: localFilePath, reason: null };
  } catch (error) {
    console.error(`Error writing to hotdir: ${error} for URL: ${url}`);
    return { success: false, reason: error.message, fileLocation: null };
  }
}

module.exports = {
  downloadURIToFile,
};

