describe("downloadURIToFile - extension detection from Content-Type", () => {
  const { downloadURIToFile } = require("../../utils/downloadURIToFile");

  // We can't easily mock global fetch in this setup, so instead we test the helper
  // functions directly to verify the logic works correctly.

  it("extensionFromContentType should map 'application/pdf' to '.pdf'", () => {
    // Simulate what the helper function does internally
    const mimeMap = {};
    for (const [mimeType, extensions] of Object.entries(ACCEPTED_MIMES)) {
      mimeMap[mimeType] = extensions[0];
    }
    expect(mimeMap["application/pdf"]).toBe(".pdf");
    expect(mimeMap["text/csv"]).toBe(".csv");
    expect(mimeMap["application/json"]).toBe(".json");
    expect(mimeMap["text/plain"]).toBe(".txt");
  });

  it("extensionFromContentType should return null for unknown MIME types", () => {
    const mimeMap = {};
    for (const [mimeType, extensions] of Object.entries(ACCEPTED_MIMES)) {
      mimeMap[mimeType] = extensions[0];
    }
    expect(mimeMap["application/unknown"]).toBeUndefined();
    expect(mimeMap["image/gif"]).toBeUndefined();
    expect(mimeMap[null]).toBeUndefined();
    expect(mimeMap[undefined]).toBeUndefined();
  });

  it("should generate correct filename with extension for arxiv-style URL", () => {
    // Test the filename generation logic
    const slugify = require("slugify");
    const url = "https://arxiv.org/pdf/2307.10265";
    const urlObj = new URL(url);

    let filename = `${urlObj.hostname}-${slugify(
      urlObj.pathname.replace(/\//g, "-"),
      { lower: true }
    )}`;

    // Without fix: filename would be 'arxiv.org-pdf-2307.10265'
    // extname would be '.10265' which is not supported
    expect(filename).toBe("arxiv.org-pdf-2307.10265");

    // With fix: if server returns application/pdf, we append .pdf
    const detectedExtension = ".pdf"; // from Content-Type application/pdf
    if (detectedExtension && !filename.endsWith(detectedExtension)) {
      filename = filename + detectedExtension;
    }
    expect(filename).toBe("arxiv.org-pdf-2307.10265.pdf");

    // Now extname would return .pdf which IS supported
    const extname = path.extname(filename);
    expect(extname).toBe(".pdf");
  });

  it("should not append extension if filename already has it", () => {
    const slugify = require("slugify");
    const url = "https://example.com/document.pdf";
    const urlObj = new URL(url);

    let filename = `${urlObj.hostname}-${slugify(
      urlObj.pathname.replace(/\//g, "-"),
      { lower: true }
    )}`;

    // Filename already ends with .pdf
    expect(filename).toBe("example.com-document.pdf");

    const detectedExtension = ".pdf";
    if (detectedExtension && !filename.endsWith(detectedExtension)) {
      filename = filename + detectedExtension;
    }
    // Should not double-append
    expect(filename).toBe("example.com-document.pdf");
  });
});

